            return depth_memo[x]
        next_p = get_popcount(x)
        depth = 1 + compute_depth(next_p)
        depth_memo[x] = depth
        return depth

    # Precompute depth for all nums initially
    depth_list = [0] * len(nums)
    for i in range(len(nums)):
        depth_list[i] = compute_depth(nums[i])

    answer = []
    for query in queries:
        if query[0] == 1:
            _, l, r, k = query
            count = 0
            for i in range(l, r + 1):
                if depth_list[i] == k:
                    count += 1
            answer.append(count)
        elif query[0] == 2:
            _, idx, val = query
            nums[idx] = val
            depth_list[idx] = compute_depth(val)
    return answer
